// Tiny WebAudio SFX helper for subtle PS1-era UI palette
// Goal: avoid 8-bit chiptune harshness; prefer filtered, sample-like ticks and plucks
// Usage: import SFX from './utils/sfx'; SFX.play('hover')

const SFX = (() => {
  let ctx = null;
  let muted = false;
  const last = new Map();

  const ensureCtx = () => {
    if (!ctx) {
      try { ctx = new (window.AudioContext || window.webkitAudioContext)(); } catch {}
    }
    return ctx;
  };

  const throttle = (key, ms) => {
    const now = performance.now();
    const t = last.get(key) || 0;
    if (now - t < ms) return true;
    last.set(key, now);
    return false;
  };

  // PS1-ish palette building blocks
  // 1) Short filtered noise tick (for hover)
  const noiseTick = ({ dur = 0.035, gain = 0.022, center = 2200, q = 0.9 }) => {
    if (muted) return;
    const ac = ensureCtx();
    if (!ac) return;
    const t0 = ac.currentTime;
    const frames = Math.max(32, Math.floor(ac.sampleRate * dur));
    const buf = ac.createBuffer(1, frames, ac.sampleRate);
    const data = buf.getChannelData(0);
    for (let i = 0; i < frames; i++) data[i] = (Math.random() * 2 - 1) * (1 - i / frames); // small decay
    const src = ac.createBufferSource();
    src.buffer = buf;
    const bp = ac.createBiquadFilter();
    bp.type = 'bandpass';
    bp.frequency.setValueAtTime(center, t0);
    bp.Q.setValueAtTime(q, t0);
    const g = ac.createGain();
    g.gain.setValueAtTime(0.0001, t0);
    g.gain.exponentialRampToValueAtTime(gain, t0 + 0.004);
    g.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    src.connect(bp).connect(g).connect(ac.destination);
    src.start(t0);
    src.stop(t0 + dur + 0.01);
  };

  // 2) Filtered pluck: layered sine + triangle through a lowpass with quick decay
  const pluck = ({ freq = 520, dur = 0.09, gain = 0.03, cutoff = 1600, q = 0.7, detune = 6 }) => {
    if (muted) return;
    const ac = ensureCtx();
    if (!ac) return;
    const t0 = ac.currentTime;
    const lp = ac.createBiquadFilter();
    lp.type = 'lowpass';
    lp.frequency.setValueAtTime(cutoff, t0);
    lp.Q.setValueAtTime(q, t0);
    const g = ac.createGain();
    g.gain.setValueAtTime(0.0001, t0);
    g.gain.exponentialRampToValueAtTime(gain, t0 + 0.006);
    g.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    const o1 = ac.createOscillator();
    o1.type = 'sine';
    o1.frequency.setValueAtTime(freq, t0);
    const o2 = ac.createOscillator();
    o2.type = 'triangle';
    o2.frequency.setValueAtTime(freq, t0);
    o2.detune.setValueAtTime(detune, t0); // slight detune for body
    o1.connect(lp);
    o2.connect(lp);
    lp.connect(g).connect(ac.destination);
    o1.start(t0); o2.start(t0);
    o1.stop(t0 + dur + 0.02); o2.stop(t0 + dur + 0.02);
  };

  // 3) Gentle glide with filter sweep (open/close)
  const glide = ({ up = true, base = 300, spread = 140, gain = 0.028, seg = 0.08, cutoff0 = 1200, cutoff1 = 2200 }) => {
    if (muted) return;
    const ac = ensureCtx();
    if (!ac) return;
    const t0 = ac.currentTime;
    const o = ac.createOscillator();
    o.type = 'sine';
    const f0 = base + (up ? 0 : spread);
    const f1 = base + (up ? spread : 0);
    o.frequency.setValueAtTime(f0, t0);
    o.frequency.linearRampToValueAtTime(f1, t0 + seg);
    const lp = ac.createBiquadFilter();
    lp.type = 'lowpass';
    lp.frequency.setValueAtTime(up ? cutoff0 : cutoff1, t0);
    lp.frequency.linearRampToValueAtTime(up ? cutoff1 : cutoff0, t0 + seg);
    lp.Q.setValueAtTime(0.8, t0);
    const g = ac.createGain();
    g.gain.setValueAtTime(0.0001, t0);
    g.gain.exponentialRampToValueAtTime(gain, t0 + 0.008);
    g.gain.exponentialRampToValueAtTime(0.0001, t0 + seg + 0.05);
    o.connect(lp).connect(g).connect(ac.destination);
    o.start(t0);
    o.stop(t0 + seg + 0.08);
  };

  const api = {
    resume() {
      const ac = ensureCtx();
      if (ac && ac.state === 'suspended') ac.resume().catch(() => {});
    },
    setMuted(v) { muted = !!v; },
    play(kind) {
      switch (kind) {
        case 'hover':
          if (throttle('hover', 100)) return; // avoid spam on mousemove
          // Short filtered noise tick
          noiseTick({ dur: 0.03, gain: 0.02, center: 2500, q: 1.0 });
          break;
        case 'click':
          if (throttle('click', 80)) return;
          // Perceptual pluck, slightly muffled
          pluck({ freq: 520, dur: 0.075, gain: 0.028, cutoff: 1700, q: 0.9, detune: 5 });
          break;
        case 'open':
          if (throttle('open', 120)) return;
          // Soft rise with filter opening
          glide({ up: true, base: 300, spread: 150, gain: 0.028, seg: 0.075, cutoff0: 1100, cutoff1: 2300 });
          break;
        case 'close':
          if (throttle('close', 120)) return;
          // Gentle fall with filter closing
          glide({ up: false, base: 300, spread: 150, gain: 0.026, seg: 0.065, cutoff0: 1100, cutoff1: 2300 });
          break;
        default:
          // noop
          break;
      }
    }
  };

  return api;
})();

export default SFX;
